css:
.loader {
  color: var(--loader-color, #ec4899);
  --loader-secondary-color: #f9a8d4;
  --loader-bg: #ffffff;
width: 45px;
aspect-ratio: 1;
--c: conic-gradient(from -90deg,currentColor 90deg,#0000 0);
background: var(--c), var(--c);
background-size: 40% 40%;
animation: l19 1s infinite alternate;
}
@keyframes l19 {
0%,
10% {background-position: 0 0,0 calc(100%/3)}
50% {background-position: 0 0,calc(100%/3) calc(100%/3)}
90%,
100% {background-position: 0 0,calc(100%/3) 0}
}
